#include<bits/stdc++.h>
using namespace std;
int main() {
	int n,a[101],num=0,d,t[20001];
	cin>>n;
	for(int i=1;i<=n;i++){
		cin>>a[i];
	}for(int i=1;i<=n;i++){
		for(int j=1;j<=n;j++){
			t[a[i]+a[j]]++;
		}
	}for(int i=1;i<=n;i++){
		if(t[a[i]]!=0){
			num++;
		}
	}cout<<num;
	return 0;
}
